<?php
 namespace WPAICG\Chat\Storage; use WPAICG\Chat\Storage\LogQueryHelper; use WPAICG\Chat\Storage\ReaderMethods; if (!defined('ABSPATH')) { exit; } require_once __DIR__ . '/reader/methods.php'; class ConversationReader { private $wpdb; private $table_name; private $query_helper; public function __construct() { global $wpdb; $this->wpdb = $wpdb; $this->table_name = $wpdb->prefix . 'aipkit_chat_logs'; $this->query_helper = new LogQueryHelper($this->table_name); } public function get_wpdb(): \wpdb { return $this->wpdb; } public function get_table_name(): string { return $this->table_name; } public function get_query_helper(): LogQueryHelper { return $this->query_helper; } public function get_conversation_thread_history(?int $user_id, ?string $session_id, int $bot_id, string $conversation_uuid): array { return ReaderMethods\get_conversation_thread_history_logic($this, $user_id, $session_id, $bot_id, $conversation_uuid); } public function get_all_conversation_data(?int $user_id, ?string $session_id, int $bot_id): ?array { return ReaderMethods\get_all_conversation_data_logic($this, $user_id, $session_id, $bot_id); } } 